    public Object parseWsOrderStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "wait", "open" );
            put( "done", "closed" );
            put( "cancel", "canceled" );
            put( "watch", "open" );
            put( "trade", "open" );
        }};
        if (Helpers.isTrue(Helpers.isEqual(status, null)))
        {
            return null;
        }
        return this.safeString(statuses, status, status);
    }

    public Object parseWsOrder(Object order, Object... optionalArgs)
    {
        //
        // {
        //     "type": "myOrder",
        //     "code": "SGD-XRP",
        //     "uuid": "ac2dc2a3-fce9-40a2-a4f6-5987c25c438f",
        //     "ask_bid": "BID",
        //     "order_type": "limit",
        //     "state": "trade",
        //     "price": 0.001453,
        //     "avg_price": 0.00145372,
        //     "volume": 30925891.29839369,
        //     "remaining_volume": 29968038.09235948,
        //     "executed_volume": 30925891.29839369,
        //     "trades_count": 1,
        //     "reserved_fee": 44.23943970238218,
        //     "remaining_fee": 21.77177967409916,
        //     "paid_fee": 22.467660028283017,
        //     "locked": 43565.33112787242,
        //     "executed_funds": 44935.32005656603,
        //     "order_timestamp": 1710751590000,
        //     "timestamp": 1710751597500,
        //     "stream_type": "REALTIME"
        // }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object id = this.safeString(order, "uuid");
        Object side = this.safeStringLower(order, "ask_bid");
        if (Helpers.isTrue(Helpers.isEqual(side, "bid")))
        {
            side = "buy";
        } else
        {
            side = "sell";
        }
        Object timestamp = this.parse8601(this.safeString(order, "order_timestamp"));
        Object status = this.parseWsOrderStatus(this.safeString(order, "state"));
        Object marketId = this.safeString(order, "code");
        market = this.safeMarket(marketId, market);
        Object fee = null;
        Object feeCost = this.safeString(order, "paid_fee");
        if (Helpers.isTrue(!Helpers.isEqual(feeCost, null)))
        {
            final Object finalMarket = market;
            final Object finalFeeCost = feeCost;
            fee = new java.util.HashMap<String, Object>() {{
                put( "currency", Helpers.GetValue(finalMarket, "quote") );
                put( "cost", finalFeeCost );
            }};
        }
        final Object finalMarket_2 = market;
        final Object finalSide = side;
        final Object finalFee = fee;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "info", order );
            put( "id", id );
            put( "clientOrderId", null );
            put( "timestamp", timestamp );
            put( "datetime", UpbitCore.this.iso8601(timestamp) );
            put( "lastTradeTimestamp", UpbitCore.this.safeString(order, "trade_timestamp") );
            put( "symbol", Helpers.GetValue(finalMarket_2, "symbol") );
            put( "type", UpbitCore.this.safeString(order, "order_type") );
            put( "timeInForce", UpbitCore.this.safeString(order, "time_in_force") );
            put( "postOnly", null );
            put( "side", finalSide );
            put( "price", UpbitCore.this.safeString(order, "price") );
            put( "stopPrice", null );
            put( "triggerPrice", null );
            put( "cost", UpbitCore.this.safeString(order, "executed_funds") );
            put( "average", UpbitCore.this.safeString(order, "avg_price") );
            put( "amount", UpbitCore.this.safeString(order, "volume") );
            put( "filled", UpbitCore.this.safeString(order, "executed_volume") );
            put( "remaining", UpbitCore.this.safeString(order, "remaining_volume") );
            put( "status", status );
            put( "fee", finalFee );
            put( "trades", null );
        }});
    }

